19Рєњ// Shared normalization helpers
20Рєњ
21Рєњfunction trimString(input: unknown): string | undefined {
22Рєњ  if (typeof input !== "string") return undefined;
23Рєњ  const trimmed = input.trim();
24Рєњ  return trimmed || undefined;
25Рєњ}
