27Рєњfunction normalizeBoolean(input: unknown): boolean | undefined {
28Рєњ  if (typeof input === "boolean") return input;
29Рєњ  if (typeof input === "number") {
30Рєњ    if (input === 1) return true;
31Рєњ    if (input === 0) return false;
32Рєњ    return undefined;
33Рєњ  }
34Рєњ  if (typeof input !== "string") return undefined;
35Рєњ  const normalized = input.trim().toLowerCase();
36Рєњ  if (!normalized) return undefined;
37Рєњ  if (["true", "yes", "y", "1", "open", "available", "oui"].includes(normalized)) return true;
38Рєњ  if (["false", "no", "n", "0", "closed", "unavailable", "non"].includes(normalized)) return false;
39Рєњ  return undefined;
40Рєњ}
41Рєњ
42Рєњfunction normalizeInteger(input: unknown): number | undefined {
43Рєњ  if (typeof input === "number" && Number.isFinite(input)) return Math.round(input);
44Рєњ  if (typeof input === "string" && input.trim()) {
45Рєњ    const parsed = Number(input);
46Рєњ    if (Number.isFinite(parsed)) return Math.round(parsed);
47Рєњ  }
48Рєњ  return undefined;
49Рєњ}
50Рєњ
51Рєњfunction normalizeStringArray(input: unknown): string[] | undefined {
52Рєњ  if (Array.isArray(input)) {
53Рєњ    const list = input
54Рєњ      .map((value) => trimString(value))
55Рєњ      .filter((value): value is string => Boolean(value));
56Рєњ    return list.length ? Array.from(new Set(list)) : undefined;
57Рєњ  }
58Рєњ  const single = trimString(input);
59Рєњ  return single ? [single] : undefined;
60Рєњ}
